\displaystyle{\begin{aligned}
   {\frac{3}{\frac{6}{y}-\frac{4}{y+4}}} 
      \amp = {\frac{3}{\frac{6}{y}-\frac{4}{y+4}}} \cdot \frac{{y\mathopen{}\left(y+4\right)}}{{y\mathopen{}\left(y+4\right)}} \\
      \amp = {\frac{3y\mathopen{}\left(y+4\right)}{\frac{6}{y}y\mathopen{}\left(y+4\right)-\frac{4}{y+4}y\mathopen{}\left(y+4\right)}} \\
      \amp = {\frac{3y\mathopen{}\left(y+4\right)}{6\mathopen{}\left(y+4\right)-4y}}, y\ne 0 \text{ and } y\ne -4 \\
      \amp = {\frac{3y\mathopen{}\left(y+4\right)}{6y+24-4y}}, y\ne 0 \text{ and } y\ne -4 \\
      \amp = \frac{3 y (y+4)}{2 y + 24}, y \ne 0 \text{ and } y \ne -4\\
      \amp = {\frac{3y\mathopen{}\left(y+4\right)}{2\mathopen{}\left(y+12\right)}, y\ne 0\hbox{ and }y\ne -4}
\end{aligned}
    }
